import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.io.File;
import android.provider.Settings;

filePath = tasker.getVariable("evtprm1");
if (filePath == null || filePath.isEmpty()) {
    throw new JavaCodeException("No file path received in %evtprm1.");
}

appPackage = tasker.getVariable("app_package");
if (appPackage == null || appPackage.isEmpty()) {
    throw new JavaCodeException("No app package received in %app_package.");
}

file = new File(filePath);
fileName = file.getName();

if (!fileName.toLowerCase().endsWith(".mp4")) {
    return;
}

renameFile(targetFile, pkg) {
    name = targetFile.getName();
    mutexKey = "tasker_lock_" + name.replaceAll("[^a-zA-Z0-9]", "_");

    if ("1".equals(tasker.getVariable(mutexKey))) {
        return;
    }
    tasker.setVariable(mutexKey, "1");

    Thread.sleep(1000);

    if (!targetFile.exists() || targetFile.length() == 0) {
        tasker.setVariable(mutexKey, null);
        throw new JavaCodeException("File not found or empty: " + targetFile.getPath());
    }

    nameWithoutExt = name.substring(0, name.lastIndexOf("."));
    newFile = new File(targetFile.getParent(), nameWithoutExt + "_" + pkg + ".mp4");

    success = targetFile.renameTo(newFile);
    tasker.setVariable(mutexKey, null);

    if (!success) {
        throw new JavaCodeException("Failed to rename file to: " + newFile.getName());
    }

    systemLocale = Settings.System.getString(context.getContentResolver(), "system_locales");
    lang = (systemLocale != null && systemLocale.length() >= 2) ? systemLocale.substring(0, 2).toLowerCase() : "en";

    if (lang.equals("pt")) {
        msg = "Gravação de tela nomeada";
    } else if (lang.equals("es")) {
        msg = "Grabación de pantalla nombrada";
    } else {
        msg = "Screen recording named";
    }

    tasker.setVariable("recording_msg", msg);
    tasker.setVariable("new_recording_name", newFile.getName());
}

/* ── Non-pending file: custom ROM or stock ROM second event ── */
if (!fileName.startsWith(".pending")) {
    if (!fileName.contains("_" + appPackage + ".mp4")) {
        renameFile(file, appPackage);
    }
    return;
}

/* ── First .pending: recording started, store flag and exit ── */
if (recordingPending == null || recordingPending == void) {
    tasker.setJavaVariable("recordingPending", "1");
    return;
}

/* ── Second .pending: recording ended, poll for final file ── */
dir = file.getParentFile();
finalFile = null;

for (int i = 0; i < 10; i++) {
    Thread.sleep(500);

    if (file.exists()) {
        continue;
    }

    files = dir.listFiles();
    if (files == null) {
        break;
    }

    newestFile = null;
    newestTime = 0;

    for (int j = 0; j < files.length; j++) {
        candidate = files[j];
        candidateName = candidate.getName();

        if (!candidateName.toLowerCase().endsWith(".mp4")) {
            continue;
        }
        if (candidateName.startsWith(".pending")) {
            continue;
        }
        if (candidateName.contains("_" + appPackage + ".mp4")) {
            continue;
        }
        if (candidate.lastModified() > newestTime) {
            newestTime = candidate.lastModified();
            newestFile = candidate;
        }
    }

    finalFile = newestFile;
    break;
}

tasker.setJavaVariable("recordingPending", null);

if (finalFile == null) {
    tasker.log("Polling timeout: final file not found for " + appPackage);
    return;
}

renameFile(finalFile, appPackage);

import android.os.Environment;
import java.io.File;

base = Environment.getExternalStorageDirectory().getAbsolutePath();

screenshotCandidates = new String[]{
    base + "/DCIM/Screenshots",
    base + "/Pictures/Screenshots",
    base + "/Pictures/ScreenShots",
    base + "/MIUI/Gallery/Pictures/Screenshots",
    base + "/Screenshots",
};
screenshotPath = base + "/DCIM/Screenshots";
for (int i = 0; i < screenshotCandidates.length; i++) {
    dir = new File(screenshotCandidates[i]);
    if (dir.exists() && dir.isDirectory()) { screenshotPath = screenshotCandidates[i]; break; }
}

recordingCandidates = new String[]{
    base + "/DCIM/ScreenRecorder",
    base + "/DCIM/ScreenRecordings",
    base + "/DCIM/Screen recordings",
    base + "/Movies/ScreenRecorder",
    base + "/Movies/ScreenRecordings",
    base + "/Movies/Screen recordings",
    base + "/Movies",
    base + "/Videos/ScreenRecordings",
    base + "/MIUI/Gallery/Videos/ScreenRecordings",
    base + "/ScreenRecordings",
};
screenRecordingPath = base + "/DCIM/ScreenRecorder";
for (int i = 0; i < recordingCandidates.length; i++) {
    dir = new File(recordingCandidates[i]);
    if (dir.exists() && dir.isDirectory()) { screenRecordingPath = recordingCandidates[i]; break; }
}

tasker.setVariable("screenshots_path", screenshotPath);
tasker.setVariable("recordings_path", screenRecordingPath);
